import React from 'react';
import { useEffect, useState } from 'react';

const Details = (user) =>{

    const showdetails = () =>{
       let url = "http://localhost:3333/user/"+user.id;

       
    }

    useEffect(() =>{
      showdetails();
    },[1])

    return (
       <>
         <ul className='text-center'>
            <h2> User Details</h2>
            <h3>user.name </h3>
            <h3>user.email</h3>
            <h3>user.mobile</h3>
         </ul>
       </>
    )
}

export default Details;
